import { Vex } from '@vex_dev/sdk';

const vex = new Vex({
  apiKey: process.env.VEX_API_KEY,
  projectId: 'fintech-flowise-project'
});

// In Flowise chatflow config
const flowiseCallback = async (input: any, output: any) => {
  const guardrailResult = await vex.run([
    {
      type: 'output',
      name: 'financial-advice-validator',
      input: output,
      config: {
        schema: {
          type: 'object',
          properties: {
            disclaimer: { type: 'string', pattern: '.*investment.*risk.*' },
            amount: { type: 'number', maximum: 1000000 }
          },
          required: ['disclaimer']
        }
      }
    }
  ], { trace_id: input.sessionId });
  return guardrailResult.pass ? output : { error: 'Compliance check failed' };
};

// Attach to Flowise flow
const chatflow = new Chatflow();
chatflow.setCallback(flowiseCallback);

const encryptionGuard = async (docs: any[]) => {
  const results = await vex.run([
    {
      type: 'custom',
      name: 'pci-encryption-check',
      input: docs,
      config: {
        rules: [
          {
            type: 'regex',
            pattern: '\\b(?:\\d[ -]*?){13,16}\\b',
            action: 'block',
            risk: 'pci-violation'
          },
          {
            type: 'encryption',
            required: true,
            fields: ['cardNumber', 'cvv']
          }
        ]
      }
    }
  ]);
  return results.pass ? docs : [];
};

// Flowise vector store node callback
vectorStoreNode.setPreRetrievalCallback(encryptionGuard);

const agentHandoffGuard = async (context: any, decision: any) => {
  const guardrails = await vex.run([
    {
      type: 'context',
      name: 'credit-decision-explainability',
      input: { context, decision },
      config: {
        requireFields: ['reasoning', 'factors'],
        maxContextLoss: 0.1
      }
    },
    {
      type: 'output',
      name: 'aml-screening',
      input: decision,
      config: {
        riskScoreThreshold: 0.7,
        flags: ['suspicious_pattern']
      }
    }
  ], { trace_id: context.sessionId });

  if (!guardrails.pass) {
    throw new Error('Agent handoff failed compliance: ' + guardrails.issues);
  }
  return { ...decision, explanation: guardrails.explanation };
};

// Apply to sequential agent nodes
agent1.setHandoffCallback(agentHandoffGuard);
